@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800;900&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

/* Force scrollbar to always be present to prevent layout shifts */
html {
  overflow-y: scroll !important;
  scrollbar-gutter: stable;
}

body {
  overflow-x: hidden !important;
  width: 100vw !important;
  position: relative;
}

/* Optimize animations for smooth performance */
* {
  /* Improve rendering performance */
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* GPU acceleration for motion elements */
[data-framer-motion] {
  transform: translateZ(0);
  backface-visibility: hidden;
  perspective: 1000px;
}

/* Smooth scrolling without lag */
html {
  scroll-behavior: auto;
}

/* Infinite scroll animation for client logos */
@keyframes infinite-scroll {
  0% {
    transform: translateX(0);
  }
  100% {
    transform: translateX(-50%);
  }
}

/* Reverse infinite scroll animation for RTL languages */
@keyframes infinite-scroll-rtl {
  0% {
    transform: translateX(-50%);
  }
  100% {
    transform: translateX(0);
  }
}

.animate-infinite-scroll {
  animation: infinite-scroll 40s linear infinite;
}

.animate-infinite-scroll-rtl {
  animation: infinite-scroll-rtl 40s linear infinite;
}

.animate-infinite-scroll.paused,
.animate-infinite-scroll-rtl.paused {
  animation-play-state: paused;
}

/* Reduce motion for users who prefer it */
@media (prefers-reduced-motion: reduce) {
  * {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
  }

  .animate-infinite-scroll,
  .animate-infinite-scroll-rtl {
    animation: none;
  }
}

/* RTL (Right-to-Left) Support for Arabic */
[dir="rtl"] {
  direction: rtl;
  text-align: right;
}

[dir="rtl"] .text-left {
  text-align: right;
}

[dir="rtl"] .text-right {
  text-align: left;
}

[dir="rtl"] .ml-auto {
  margin-left: 0;
  margin-right: auto;
}

[dir="rtl"] .mr-auto {
  margin-right: 0;
  margin-left: auto;
}

[dir="rtl"] .pl-4 {
  padding-left: 0;
  padding-right: 1rem;
}

[dir="rtl"] .pr-4 {
  padding-right: 0;
  padding-left: 1rem;
}

[dir="rtl"] .border-l {
  border-left: none;
  border-right: 1px solid;
}

[dir="rtl"] .border-r {
  border-right: none;
  border-left: 1px solid;
}

/* RTL Navigation adjustments */
[dir="rtl"] .justify-end {
  justify-content: flex-start;
}

[dir="rtl"] .justify-start {
  justify-content: flex-end;
}

/* RTL Form adjustments */
[dir="rtl"] input,
[dir="rtl"] textarea,
[dir="rtl"] select {
  text-align: right;
}

/* RTL Button icon adjustments */
[dir="rtl"] .lucide {
  transform: scaleX(-1);
}

[dir="rtl"] .rotate-180 {
  transform: rotate(0deg);
}

/* Completely isolate dropdown content from page layout */
[data-radix-select-content] {
  position: fixed !important;
  z-index: 9999 !important;
  transform: translateZ(0) !important; /* Force hardware acceleration */
  contain: layout style paint !important; /* Isolate from document flow */
}

/* Prevent any layout reflow during dropdown interactions */
[data-radix-select-trigger] {
  contain: layout !important;
}

/* Create stacking context to isolate filters */
.filters-section {
  isolation: isolate;
  contain: layout style;
}

/* Hero Section Backgrounds with Image Management System IDs */
/* ID-831: About page hero - Industrial automation facility background */
.hero-bg-about {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* ID-832: Services page hero - Process automation systems background */
.hero-bg-services {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* ID-833: Products page hero - Industrial equipment showcase background */
.hero-bg-products {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* ID-834: Projects page hero - Power plant construction background */
.hero-bg-projects {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* ID-835: Contact page hero - Professional office meeting background */
.hero-bg-contact {
  background-image: url('data:image/svg+xml;base64,');
  background-size: cover;
  background-position: center;
  background-repeat: no-repeat;
}

/* ID-836: News page hero - Modern office environment background */
.hero-bg-news {
