                  </Card>
                );
              })}
            </div>

            {/* Emergency Support */}
            <Card className="mt-8 sm:mt-12 bg-gradient-to-br from-primary to-blue-800 text-white border-none">
              <CardContent className="p-6 sm:p-8 text-center">
