        ...prev,
        additionalFeatures: [...prev.additionalFeatures, featureId],
      }));
    } else {
      setConfig((prev) => ({
        ...prev,
        additionalFeatures: prev.additionalFeatures.filter(
          (id) => id !== featureId,
