          postalCode: "201301",
          addressCountry: "IN",
        },
      },
      serviceType: "Industrial Automation Consultation",
      areaServed: "India",
      availableChannel: {
        "@type": "ServiceChannel",
        serviceUrl: "https://powertonengineering.in/quote",
        serviceSmsNumber: "+91-94627-71662",
        servicePhone: "+91-94627-71662",
      },
    },
  };

  return (
