                                    {PROJECT_TYPES.map((type) => (
                                      <SelectItem
                                        key={type.value}
                                        value={type.value}
                                      >
                                        {t(`pages:quote.projectTypes.${type.label}`)}
                                      </SelectItem>
                                    ))}
                                  </SelectContent>
                                </Select>
                              </div>

                              <div>
                                <Label
                                  htmlFor="industry"
                                  className="text-sm font-medium mb-2 block"
                                >
                                  {t("common:labels.industry")}
                                </Label>
                                <Select
                                  value={config.industry}
                                  onValueChange={(value) =>
                                    setConfig((prev) => ({
                                      ...prev,
                                      industry: value,
                                    }))
                                  }
                                >
                                  <SelectTrigger>
                                    <SelectValue
                                      placeholder={t(
                                        "common:placeholders.selectIndustry",
                                      )}
                                    />
                                  </SelectTrigger>
                                  <SelectContent>
                                    {INDUSTRIES.map((industry) => (
                                      <SelectItem
                                        key={industry.value}
                                        value={industry.value}
                                      >
                                        {t(`pages:quote.industries.${industry.label}`)}
                                      </SelectItem>
                                    ))}
                                  </SelectContent>
                                </Select>
                              </div>
                            </>
                          )}

                          {/* Step 2: Project Specifications */}
                          {currentStep === 2 && (
                            <>
                              <div>
                                <Label
                                  htmlFor="projectSize"
                                  className="text-sm font-medium mb-2 block"
                                >
                                  Project Size
                                </Label>
                                <Select
                                  value={config.projectSize}
                                  onValueChange={(value) =>
                                    setConfig((prev) => ({
                                      ...prev,
                                      projectSize: value,
                                    }))
                                  }
                                >
                                  <SelectTrigger>
                                    <SelectValue
                                      placeholder={t(
                                        "common:placeholders.selectProjectSize",
                                      )}
                                    />
                                  </SelectTrigger>
                                  <SelectContent>
                                    {PROJECT_SIZES.map((size) => (
                                      <SelectItem
                                        key={size.value}
                                        value={size.value}
                                      >
                                        {t(`pages:quote.projectSizes.${size.label}`)}
                                      </SelectItem>
                                    ))}
                                  </SelectContent>
                                </Select>
                              </div>

                              <div>
                                <Label
                                  htmlFor="timeline"
                                  className="text-sm font-medium mb-2 block"
                                >
                                  Project Timeline
                                </Label>
                                <Select
                                  value={config.timeline}
                                  onValueChange={(value) =>
                                    setConfig((prev) => ({
                                      ...prev,
                                      timeline: value,
                                    }))
                                  }
                                >
                                  <SelectTrigger>
                                    <SelectValue
                                      placeholder={t(
                                        "common:placeholders.selectTimeline",
                                      )}
                                    />
                                  </SelectTrigger>
                                  <SelectContent>
                                    {TIMELINES.map((timeline) => (
                                      <SelectItem
                                        key={timeline.value}
                                        value={timeline.value}
                                      >
                                        {t(`pages:quote.timelines.${timeline.label}`)}
                                      </SelectItem>
                                    ))}
                                  </SelectContent>
                                </Select>
                              </div>
                            </>
                          )}

                          {/* Step 3: Requirements & Features */}
                          {currentStep === 3 && (
                            <div className="space-y-6">
                              <div>
                                <Label className="text-sm font-medium mb-4 block">
                                  Core Requirements
                                </Label>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                  {REQUIREMENTS.map((requirement) => (
                                    <div
                                      key={requirement.id}
                                      className="flex items-center space-x-3"
                                    >
                                      <Checkbox
                                        id={requirement.id}
                                        checked={config.requirements.includes(
                                          requirement.id,
                                        )}
                                        onCheckedChange={(checked) =>
                                          handleRequirementChange(
                                            requirement.id,
                                            checked as boolean,
                                          )
                                        }
                                      />
                                      <div>
                                        <Label
                                          htmlFor={requirement.id}
                                          className="text-sm font-medium cursor-pointer"
                                        >
                                          {t(`pages:quote.requirements.${requirement.label}`)}
                                        </Label>
                                        <div className="text-xs text-muted-foreground">
                                          {formatCurrency(requirement.price)}
                                        </div>
                                      </div>
                                    </div>
                                  ))}
                                </div>
                              </div>

                              <div>
                                <Label className="text-sm font-medium mb-4 block">
                                  Additional Features
                                </Label>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                  {ADDITIONAL_FEATURES.map((feature) => (
                                    <div
                                      key={feature.id}
                                      className="flex items-center space-x-3"
                                    >
                                      <Checkbox
                                        id={feature.id}
                                        checked={config.additionalFeatures.includes(
                                          feature.id,
                                        )}
                                        onCheckedChange={(checked) =>
                                          handleFeatureChange(
                                            feature.id,
                                            checked as boolean,
                                          )
                                        }
                                      />
                                      <div>
                                        <Label
                                          htmlFor={feature.id}
                                          className="text-sm font-medium cursor-pointer"
                                        >
                                          {t(`pages:quote.additionalFeatures.${feature.label}`)}
                                        </Label>
                                        <div className="text-xs text-muted-foreground">
                                          {formatCurrency(feature.price)}
                                        </div>
                                      </div>
                                    </div>
                                  ))}
                                </div>
                              </div>
                            </div>
                          )}

                          {/* Step 4: Additional Information */}
                          {currentStep === 4 && (
                            <>
                              <div>
                                <Label
                                  htmlFor="location"
                                  className="text-sm font-medium mb-2 block"
                                >
                                  Project Location
                                </Label>
                                <Input
                                  id="location"
                                  placeholder={t(
                                    "common:placeholders.cityState",
                                  )}
                                  value={config.location}
                                  onChange={(e) =>
                                    setConfig((prev) => ({
                                      ...prev,
                                      location: e.target.value,
                                    }))
                                  }
                                />
                              </div>

                              <div>
                                <Label
                                  htmlFor="existingInfrastructure"
                                  className="text-sm font-medium mb-2 block"
                                >
                                  Existing Infrastructure
                                </Label>
                                <Textarea
                                  id="existingInfrastructure"
                                  placeholder={t(
                                    "common:placeholders.describeExisting",
                                  )}
                                  value={config.existingInfrastructure}
                                  onChange={(e) =>
                                    setConfig((prev) => ({
                                      ...prev,
                                      existingInfrastructure: e.target.value,
                                    }))
                                  }
                                  rows={4}
                                />
                              </div>
                            </>
                          )}

                          {/* Navigation Buttons */}
                          <div className="flex justify-between pt-6 border-t">
                            <Button
                              variant="outline"
                              onClick={prevStep}
                              disabled={currentStep === 1}
                              className="border-2 border-primary text-primary hover:bg-primary hover:text-primary-foreground"
                            >
                              <ArrowLeft className="w-4 h-4 mr-2" />
                              Previous
                            </Button>
                            <Button
                              onClick={nextStep}
                              disabled={
                                currentStep === 1 &&
                                (!config.projectType || !config.industry)
                              }
                              className="bg-primary hover:bg-primary/90 text-primary-foreground"
                            >
                              {currentStep === 4 ? "Complete" : "Next"}
                              {currentStep !== 4 && (
                                <ArrowRight className="w-4 h-4 ml-2" />
                              )}
                            </Button>
                          </div>
                        </CardContent>
                        </Card>
                      </motion.div>
                    </div>

                    {/* Cost Estimate Panel */}
                    <div>
                      <Card className="bg-card border border-border rounded-lg shadow-sm sticky top-8">
                        <CardHeader className="p-6">
                          <CardTitle className="text-xl md:text-2xl font-semibold text-foreground flex items-center">
                            <IndianRupee className="w-6 h-6 mr-2 text-secondary" />
                            Cost Estimate
                          </CardTitle>
                        </CardHeader>
                        <CardContent className="p-6 space-y-4">
                          {config.projectType && config.industry && (
                            <>
                              <div className="space-y-3">
                                <div className="flex justify-between items-center">
                                  <span className="text-sm text-muted-foreground">
                                    Base Project Cost:
                                  </span>
                                  <span className="font-medium">
                                    {formatCurrency(estimate.basePrice)}
                                  </span>
                                </div>

                                {estimate.requirementsCost > 0 && (
                                  <div className="flex justify-between items-center">
                                    <span className="text-sm text-muted-foreground">
                                      Requirements:
                                    </span>
                                    <span className="font-medium">
                                      {formatCurrency(
                                        estimate.requirementsCost,
                                      )}
                                    </span>
                                  </div>
                                )}

                                {estimate.featuresCost > 0 && (
                                  <div className="flex justify-between items-center">
                                    <span className="text-sm text-muted-foreground">
                                      Additional Features:
                                    </span>
                                    <span className="font-medium">
                                      {formatCurrency(estimate.featuresCost)}
                                    </span>
                                  </div>
                                )}

                                <div className="border-t pt-3">
                                  <div className="flex justify-between items-center">
                                    <span className="font-semibold text-foreground">
                                      Total Estimate:
                                    </span>
                                    <span className="text-2xl font-bold text-secondary">
                                      {formatCurrency(estimate.totalCost)}
                                    </span>
                                  </div>
                                </div>
                              </div>

                              <div className="mt-6 p-4 bg-muted rounded-lg">
                                <div className="text-sm text-muted-foreground">
                                  <div className="flex items-center gap-2 mb-2">
                                    <Clock className="w-4 h-4" />
                                    <span>
                                      Estimated Timeline: {estimate.timeline}
                                    </span>
                                  </div>
                                  <div className="flex items-center gap-2">
                                    <CheckCircle className="w-4 h-4 text-green-600" />
                                    <span>
                                      Includes installation & commissioning
                                    </span>
                                  </div>
                                </div>
                              </div>

                              <Button className="w-full bg-secondary hover:bg-secondary/90 text-secondary-foreground mt-6">
                                <Download className="w-4 h-4 mr-2" />
                                {t("common:buttons.download")}
                                Get Detailed Quote
                              </Button>
                            </>
                          )}

                          {(!config.projectType || !config.industry) && (
                            <div className="text-center py-8">
                              <Calculator className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                              <p className="text-sm text-muted-foreground">
                                Select project type and industry to see cost
                                estimates
                              </p>
                            </div>
                          )}
                        </CardContent>
                      </Card>
                    </div>
                  </div>
                </div>
                {/* Close disabled content wrapper */}
              </TabsContent>

              <TabsContent value="quote" className="space-y-8">
                {/* Quote Form Section */}
                <div className="max-w-4xl mx-auto">
                  <Card className="bg-card border border-border rounded-lg shadow-sm hover:shadow-md transition-all duration-300">
                    <CardHeader className="p-6">
                      <CardTitle className="text-xl md:text-2xl font-semibold text-foreground">
                        Request Custom Quote
                      </CardTitle>
                      <p className="text-muted-foreground">
                        Get a detailed quote tailored to your specific project
                        requirements from our engineering experts.
                      </p>
                    </CardHeader>
                    <CardContent className="p-6">
                      <FrontendQuoteForm />
                    </CardContent>
                  </Card>
                </div>
              </TabsContent>
            </Tabs>
          </div>
        </section>
      </AnimatedSection>

      {/* Benefits Section */}
      <AnimatedSection animation="fadeInUp" delay={0.3}>
        <section className="py-12 md:py-16 lg:py-20 bg-muted/30">
          <div className="max-w-7xl mx-auto px-4 md:px-6 lg:px-8">
            <div className="text-center mb-16">
              <h2 className="text-3xl lg:text-4xl font-bold text-foreground mb-6">
                Why Choose Our Quote Service?
              </h2>
              <p className="text-xl text-muted-foreground max-w-3xl mx-auto">
                Get accurate pricing and professional consultation for your
                engineering projects with our comprehensive quote service.
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
              {benefits.map((benefit, index) => {
                const Icon = benefit.icon;
                return (
                  <Card
                    key={index}
                    className="bg-card border border-border rounded-lg p-6 shadow-sm hover:shadow-md text-center hover:scale-[1.02] transition-all duration-300"
                  >
                    <div className="w-16 h-16 bg-gradient-to-br from-primary to-secondary rounded-lg flex items-center justify-center mx-auto mb-4">
                      <Icon className="w-8 h-8 text-primary-foreground" />
                    </div>
                    <h3 className="text-xl md:text-2xl font-semibold text-foreground mb-3">
                      {benefit.title}
                    </h3>
                    <p className="text-muted-foreground">
                      {benefit.description}
                    </p>
                  </Card>
                );
              })}
            </div>
          </div>
        </section>
      </AnimatedSection>

      {/* Process Steps */}
      <AnimatedSection animation="fadeInUp" delay={0.4}>
        <section className="py-12 md:py-16 lg:py-20 bg-background">
          <div className="max-w-7xl mx-auto px-4 md:px-6 lg:px-8">
            <div className="text-center mb-16">
              <h2 className="text-3xl lg:text-4xl font-bold text-foreground mb-6">
                {t('pages:quote.process.title', 'Our Quote Process')}
              </h2>
              <p className="text-xl text-muted-foreground max-w-3xl mx-auto">
                {t('pages:quote.process.description', 'From initial request to detailed proposal, we ensure a smooth and transparent process.')}
              </p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
              {processSteps.map((step, index) => (
                <div key={index} className="relative">
                  <div className="text-center">
                    <div className="w-16 h-16 bg-gradient-to-br from-primary to-secondary rounded-full flex items-center justify-center mx-auto mb-4 text-primary-foreground font-bold text-xl">
                      {step.step}
                    </div>
                    <h3 className="text-xl md:text-2xl font-semibold text-foreground mb-3">
                      {step.title}
                    </h3>
                    <p className="text-muted-foreground">{step.description}</p>
                  </div>
                  {index < processSteps.length - 1 && (
                    <div className="hidden lg:block absolute top-8 left-full w-full">
                      <div className="w-full h-0.5 bg-gradient-to-r from-primary to-secondary opacity-30"></div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </section>
      </AnimatedSection>

      {/* Call to Action */}
      <AnimatedSection animation="fadeInUp" delay={0.5}>
        <section className="py-12 md:py-16 lg:py-20 bg-primary text-white">
          <div className="max-w-7xl mx-auto px-4 md:px-6 lg:px-8 text-center">
            <h2 className="text-3xl md:text-4xl font-bold text-foreground mb-4">
              {t('pages:quote.cta.title', 'Ready to Get Started?')}
            </h2>
            <p className="text-base md:text-lg text-primary-foreground mb-8 max-w-2xl mx-auto opacity-90">
              {t('pages:quote.cta.description', 'Contact us today for your custom engineering solution. Our team is ready to help bring your project to life.')}
            </p>
            <div className="flex flex-col sm:flex-row gap-4 justify-center">
              <Button
                className="bg-secondary hover:bg-secondary/90 text-secondary-foreground px-6 py-3 rounded-lg font-semibold transition-colors"
                onClick={() => handleTabChange("calculator")}
              >
                <Calculator className="w-5 h-5 mr-2" />
                Try Cost Calculator
              </Button>
              <Button
                variant="outline"
                className="border-2 border-border text-foreground bg-background hover:bg-foreground hover:text-background px-6 py-3 rounded-lg font-semibold transition-all"
                onClick={() => handleTabChange("quote")}
              >
                <FileText className="w-5 h-5 mr-2" />
                Request Custom Quote
              </Button>
            </div>
          </div>
        </section>
      </AnimatedSection>
    </>
  );
}

