                            </div>
                          </motion.div>
                        </React.Fragment>
                      );
                    }

                    return (
                      <motion.div
                        key={item.name}
                        variants={{
                          open: { opacity: 1, x: 0 },
                          closed: { opacity: 0, x: -20 },
                        }}
                        transition={{ duration: 0.3 }}
                      >
                        <Link
                          href={item.href}
                          className={`text-lg font-medium transition-colors hover-scale block ${
                            isActive(item.href)
